rust-sqlx.query_fn:
pub async fn get_user(pool: &sqlx::PgPool, id: i32) -> Result<GetUserRow, sqlx::Error> {
    sqlx::query_as!(GetUserRow, "SELECT id, name FROM users WHERE id = $1", id)
        .fetch_one(pool)
        .await
}

rust-sqlx.row_struct:
#[derive(Debug, sqlx::FromRow)]
pub struct GetUserRow {
    pub id: i32,
    pub name: String,
}

query_sql:
-- @name get_user
-- @returns :one
SELECT id, name FROM users WHERE id = $1;
